const staticData = $getWorkflowStaticData("global");
const cfData = $("Fetch Codeforces").first().json.result || [];
const lcData = $("Fetch LeetCode").first().json?.data?.topTwoContests || [];

const now = Math.floor(Date.now() / 1000);

// Use IST explicitly instead of server-local time
const d = new Date();
const istString = d.toLocaleString("en-US", { timeZone: "Asia/Kolkata" });
const dIST = new Date(istString);
const currentDay = dIST.getDay();
const currentHour = dIST.getHours();

// Build todayStr from IST date, not UTC
const istYear = dIST.getFullYear();
const istMonth = String(dIST.getMonth() + 1).padStart(2, "0");
const istDate = String(dIST.getDate()).padStart(2, "0");
const todayStr = `${istYear}-${istMonth}-${istDate}`;

let message = "";
let send = false;

// Format helper for time remaining
function getTimeRemaining(startTime) {
  const diff = startTime - now;
  const days = Math.floor(diff / (24 * 60 * 60));
  const hours = Math.floor((diff % (24 * 60 * 60)) / (60 * 60));
  if (days === 0 && hours === 0) return "in less than an hour";
  if (days === 0) return `in ${hours} hour${hours > 1 ? "s" : ""}`;
  if (hours === 0) return `in ${days} day${days > 1 ? "s" : ""}`;
  return `in ${days} day${days > 1 ? "s" : ""} and ${hours} hour${hours > 1 ? "s" : ""}`;
}

// Format helper for duration
function getDuration(seconds) {
  const h = Math.floor(seconds / 3600);
  const m = Math.floor((seconds % 3600) / 60);
  if (m === 0) return `${h} hour${h > 1 ? "s" : ""}`;
  return `${h}h ${m}m`;
}

// Find next contests
const cfUpcoming = cfData.filter(c => c.phase === "BEFORE" && c.startTimeSeconds >= now);
cfUpcoming.sort((a, b) => a.startTimeSeconds - b.startTimeSeconds);
const nextCf = cfUpcoming.length > 0 ? cfUpcoming[0] : null;

const lcUpcoming = lcData.filter(c => c.startTime >= now);
lcUpcoming.sort((a, b) => a.startTime - b.startTime);
const nextLc = lcUpcoming.length > 0 ? lcUpcoming[0] : null;

let oneHourAlerts = [];
let todayAlerts = [];

// Check Codeforces
if (nextCf) {
  const diff = nextCf.startTimeSeconds - now;
  const dur = getDuration(nextCf.durationSeconds);
  if (diff > 0 && diff <= 75 * 60) oneHourAlerts.push(`*Codeforces:* ${nextCf.name} (Duration: ${dur})`);
  if (diff > 0 && diff <= 24 * 3600) todayAlerts.push(`🔹 *Platform:* Codeforces\n🏆 *Contest:* ${nextCf.name}\n⏱️ *Starts:* ${getTimeRemaining(nextCf.startTimeSeconds)}\n⏳ *Duration:* ${dur}`);
}

// Check LeetCode
if (nextLc) {
  const diff = nextLc.startTime - now;
  const dur = getDuration(nextLc.duration);
  if (diff > 0 && diff <= 75 * 60) oneHourAlerts.push(`*LeetCode:* ${nextLc.title} (Duration: ${dur})`);
  if (diff > 0 && diff <= 24 * 3600) todayAlerts.push(`🔹 *Platform:* LeetCode\n🏆 *Contest:* ${nextLc.title}\n⏱️ *Starts:* ${getTimeRemaining(nextLc.startTime)}\n⏳ *Duration:* ${dur}`);
}

// Evaluate Conditions with Memory
if (oneHourAlerts.length > 0) {
  const alertKey = oneHourAlerts.join(",");
  if (staticData.lastOneHourAlert !== alertKey) {
    message = "🔥 *CONTEST STARTING IN 1 HOUR!* 🔥\n\n" + oneHourAlerts.join("\n");
    staticData.lastOneHourAlert = alertKey;
    send = true;
  }
}
else if (todayAlerts.length > 0 && staticData.lastContestDay !== todayStr) {
  message = "🌅 *Contests Happening Today!* Good luck:\n\n" + todayAlerts.join("\n\n");
  staticData.lastContestDay = todayStr;
  send = true;
}
else if ((currentDay === 1 || currentDay === 4) && currentHour >= 18 && staticData.lastWeeklyDay !== todayStr) {
  message = "*📅 Weekly Contest Overview*\n\n";
  if (nextCf) message += `*Codeforces:* ${nextCf.name} (Starts ${getTimeRemaining(nextCf.startTimeSeconds)} | ${getDuration(nextCf.durationSeconds)})\n`;
  if (nextLc) message += `*LeetCode:* ${nextLc.title} (Starts ${getTimeRemaining(nextLc.startTime)} | ${getDuration(nextLc.duration)})\n`;
  staticData.lastWeeklyDay = todayStr;
  send = true;
}

if (!send) {
  return []; // Stop workflow silently
}

return [{ json: { message } }];
